const CODE_TO_NAME = { 76: "Brazil", 380: "Italy", 36: "Australia", 152: "Chile" };

function CountryMap({ numericCode, caption }) {
  const name = CODE_TO_NAME[numericCode];
  const data = name ? COUNTRY_PATHS[name] : null;
  if (!data) return null;
  return (
    <div style={{ marginBottom: 14, background: "#0D1117", borderRadius: 6, overflow: "hidden", border: "1px solid #282828" }}>
      <svg viewBox={`0 0 ${data.w} ${data.h}`} style={{ width: "100%", display: "block" }}>
        <path d={data.others} fill="#1A2030" stroke="#252D3D" strokeWidth="0.6" />
        <path d={data.main}   fill="#C9A84C" stroke="#8B6914" strokeWidth="0.8" />
      </svg>
      {caption && (
        <div style={{ textAlign: "center", padding: "5px 0 9px", fontSize: "0.65rem",
                      fontFamily: "'Courier New',monospace", color: "#5A5550",
                      textTransform: "uppercase", letterSpacing: "0.1em" }}>
          {caption}
        </div>
      )}
    </div>
  );
}

const apiStorage = {
  get: async (key) => {
    const res = await fetch(`/api/storage/${encodeURIComponent(key)}`);
    if (!res.ok) throw new Error("not found");
    return res.json();
  },
  set: async (key, value) => {
    const res = await fetch("/api/storage", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ key, value }),
    });
    return res.json();
  },
  delete: async (key) => {
    const res = await fetch(`/api/storage/${encodeURIComponent(key)}`, { method: "DELETE" });
    return res.json();
  },
  list: async (prefix = "") => {
    const res = await fetch(`/api/storage?prefix=${encodeURIComponent(prefix)}`);
    return res.json();
  },
};

// --- Concurrency-safe writes -------------------------------------------------
// The shared records ("users", "leaderboard:*", "submissions:*", and the group
// blobs) each hold EVERY user inside one value. Writing back a stale in-memory
// copy lets one browser erase users it never loaded (last-write-wins data loss).
// These helpers re-fetch the latest value immediately before writing and merge
// in only the caller's single change, shrinking the race window from minutes
// (the age of a loaded tab) to milliseconds (one fetch→write round trip).
const mergeWrite = async (key, mutate, fallback) => {
  let current = fallback;
  try {
    const r = await apiStorage.get(key);
    if (r && r.value != null) current = JSON.parse(r.value);
  } catch (e) { /* key doesn't exist yet → use fallback */ }
  const next = mutate(current);
  if (next === undefined || next === null) return current; // guard: never clobber with empty
  await apiStorage.set(key, JSON.stringify(next));
  return next;
};

// Race-free write via the server's atomic Redis routes. Throws on any failure so
// callers fall back to the mergeWrite path above — the app keeps working either way.
const atomicPost = async (path, body) => {
  const res = await fetch(path, { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify(body) });
  if (!res.ok) throw new Error(`${path} ${res.status}`);
  return res.json();
};

// Merge a partial update into one user's record (streak, profile fields, groups, joined).
const mergeUser = async (username, partial) => {
  try { await atomicPost("/api/merge", { key: "users", field: username, value: partial, mode: "merge" }); }
  catch (e) { await mergeWrite("users", (o) => ({ ...(o || {}), [username]: { ...((o || {})[username] || {}), ...partial } }), {}); }
};

// Atomically claim a brand-new username at registration. Returns {ok:false} if taken.
const registerUserUnique = async (username, full) => {
  try {
    const r = await atomicPost("/api/merge", { key: "users", field: username, value: full, mode: "setnx" });
    return { ok: !(r && r.taken) };
  } catch (e) {
    let taken = false;
    await mergeWrite("users", (o) => {
      const base = o || {};
      if (base[username]) { taken = true; return base; }
      return { ...base, [username]: full };
    }, {});
    return { ok: !taken };
  }
};

// Insert/replace one entry (matched by username) in an array-blob, then sort by points desc.
const upsertEntry = async (key, entry) => {
  try { await atomicPost("/api/upsert", { key, username: entry.username, entry }); }
  catch (e) {
    await mergeWrite(key, (arr) => {
      const base = Array.isArray(arr) ? arr : [];
      const filtered = base.filter((e) => e.username !== entry.username);
      filtered.push(entry);
      filtered.sort((a, b) => b.points - a.points);
      return filtered;
    }, []);
  }
};

// Patch fields on one existing array entry (matched by username); no-op if absent.
const patchEntry = (key, username, partial) =>
  mergeWrite(key, (arr) => (Array.isArray(arr) ? arr.map((e) => (e.username === username ? { ...e, ...partial } : e)) : []), []);

// Set one field inside an object-blob (e.g. submissions[username] = sub).
const setObjField = async (key, field, value) => {
  try { await atomicPost("/api/merge", { key, field, value, mode: "set" }); }
  catch (e) { await mergeWrite(key, (o) => ({ ...(o || {}), [field]: value }), {}); }
};

// Delete one field from an object-blob (e.g. remove a user's submission).
const deleteObjField = async (key, field) => {
  try { await atomicPost("/api/merge", { key, field, mode: "del" }); }
  catch (e) { await mergeWrite(key, (o) => { const n = { ...(o || {}) }; delete n[field]; return n; }, {}); }
};

// Append a value to an array-blob if not already present (e.g. groupsub members).
const appendUnique = async (key, value) => {
  try { await atomicPost("/api/append", { key, value }); }
  catch (e) { await mergeWrite(key, (arr) => { const a = Array.isArray(arr) ? arr : []; return a.includes(value) ? a : [...a, value]; }, []); }
};

// Add/remove a member inside a group object's nested members array (preserves concurrent changes).
const mutateGroupMembers = (key, fn) =>
  mergeWrite(key, (g) => (g ? { ...g, members: fn(Array.isArray(g.members) ? g.members : []) } : g), null);

const ADMIN_PASSWORD = "whatis2026";

// Accounts that play daily but never appear on or affect any leaderboard
// (e.g. the question writer). Matched case-insensitively.
const EXCLUDED_USERS = ["tommyf10"];
const isExcludedUser = (u) => EXCLUDED_USERS.includes((u || "").toLowerCase());
// Split a board into ranked real players (by points) and host rows pinned to
// the bottom. Hosts are shown with answered/correct but no score.
const orderBoard = (lb) => {
  const arr   = lb || [];
  const real  = arr.filter(e => !isExcludedUser(e.username)).slice().sort((a, b) => b.points - a.points);
  const hosts = arr.filter(e => isExcludedUser(e.username));
  return { real, hosts };
};
